import React, { useState, useRef, useEffect } from 'react';
import * as XLSX from 'xlsx';

// Default data
const DEFAULT_OFFICE_DATA = {
  'PSTO-Ilocos Norte': {
    warning_signals: { "Laoag City": 3, "Batac City": 2, "Pagudpud": 4 },
    general_weather: 'Moderate Rain, Strong Winds',
    related_incidents: 1,
    casualties: 0,
    power_status: '3 - Partial blackout',
    communication_lines: 'Limited service',
    damage_facilities: '2 - Minor damage',
    work_suspension: false,
    assistance_provided: 'Food packs',
    remark: 'Maintain alert status and monitor flood-prone areas.',
    municipalities: ['Laoag City', 'Batac City', 'Pagudpud']
  },
  'PSTO-Ilocos Sur': {
    warning_signals: { "Vigan City": 2, "Candon City": 2, "Santa Maria": 3 },
    general_weather: 'Heavy Rain',
    related_incidents: 2,
    casualties: 1,
    power_status: '4 - Widespread blackout',
    communication_lines: 'Intermittent',
    damage_facilities: '3 - Moderate damage',
    work_suspension: true,
    assistance_provided: 'Evacuation centers',
    remark: 'Evacuation centers are open; continue assisting affected families.',
    municipalities: ['Vigan City', 'Candon City', 'Santa Maria']
  },
  'PSTO-La Union': {
    warning_signals: { "San Fernando": 4, "Bauang": 4, "Agoo": 3, "Luna": 4, "Bacnotan": 4, "Bangar": 4, "San Juan": 3 },
    general_weather: 'Severe Wind, Light Rain',
    related_incidents: 0,
    casualties: 0,
    power_status: '5 - Total blackout',
    communication_lines: 'Operational',
    damage_facilities: '0 - No damage',
    work_suspension: true,
    assistance_provided: 'None',
    remark: 'Monitor local infrastructure; keep agencies on alert.',
    municipalities: ['San Fernando', 'Bauang', 'Agoo', 'Luna', 'Bacnotan', 'Bangar', 'San Juan']
  },
  'PSTO-Pangasinan': {
    warning_signals: { "Lingayen": 1, "Dagupan": 1, "Alaminos": 1 },
    general_weather: 'Light Rain',
    related_incidents: 0,
    casualties: 0,
    power_status: '0 - No outage',
    communication_lines: 'Fully operational',
    damage_facilities: '0 - No damage',
    work_suspension: false,
    assistance_provided: 'Advisories',
    remark: 'No immediate damage; continue issuing weather advisories.',
    municipalities: ['Lingayen', 'Dagupan', 'Alaminos']
  },
};

const DEFAULT_EVENTS = [
  { id: 1, name: 'CALOY', date: 'Jun 1, 2026', alertLevel: 'RED', deployment: 'Deployed', provinces: ['Ilocos Norte'], status: 'active', category: 'Super Typhoon' },
  { id: 2, name: 'BASYANG', date: 'Jun 1, 2026', alertLevel: 'RED', deployment: 'Draft', provinces: ['Ilocos Norte'], status: 'draft', category: 'Typhoon' },
  { id: 3, name: 'ADA', date: 'Jun 1, 2026', alertLevel: 'BLUE', deployment: 'Draft', provinces: ['Ilocos Norte', 'Ilocos Sur', 'La Union', 'Pangasinan'], status: 'draft', category: 'Tropical Storm' }
];

const DEFAULT_USERS = [
  { id: 1, name: 'Admin User', email: 'admin@dostregion1.ph', office: 'PSTO-La Union', role: 'SADMIN', status: 'Active', password: 'admin123' },
  { id: 2, name: 'Regional Admin', email: 'admin-ilocosnorte@dostregion1.ph', office: 'PSTO-Ilocos Norte', role: 'ADMIN', status: 'Active', password: 'admin123' },
  { id: 3, name: 'General User', email: 'user-ilocossur@dostregion1.ph', office: 'PSTO-Ilocos Sur', role: 'USER', status: 'Active', password: 'user123' },
];

// Load/save to localStorage
const loadFromStorage = (key, defaultValue) => {
  const stored = localStorage.getItem(key);
  if (stored) {
    try { return JSON.parse(stored); } catch(e) { return defaultValue; }
  }
  return defaultValue;
};

const saveToStorage = (key, data) => localStorage.setItem(key, JSON.stringify(data));

const Dashboard = ({ onLogout, currentUser }) => {
  // State
  const [officesData, setOfficesData] = useState(() => loadFromStorage('dash_officesData', DEFAULT_OFFICE_DATA));
  const [events, setEvents] = useState(() => loadFromStorage('dash_events', DEFAULT_EVENTS));
  const [users, setUsers] = useState(() => loadFromStorage('dash_users', DEFAULT_USERS));
  const [activeMenu, setActiveMenu] = useState(() => loadFromStorage('dash_activeMenu', 'dashboard'));
  const [selectedOffice, setSelectedOffice] = useState('PSTO-La Union');
  const [editMode, setEditMode] = useState(false);
  const [formData, setFormData] = useState(null);
  const [toast, setToast] = useState({ message: '', type: 'info', visible: false });
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [isEditingEvent, setIsEditingEvent] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [showUserModal, setShowUserModal] = useState(false);
  const [isEditingUser, setIsEditingUser] = useState(false);
  const [userForm, setUserForm] = useState({ id: null, name: '', email: '', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: '' });
  const [userSearchTerm, setUserSearchTerm] = useState('');
  const toastTimerRef = useRef(null);

  const [newEvent, setNewEvent] = useState({
    id: null, name: '', alertLevel: '', category: '', deployment: 'Draft', provinces: [], status: 'pending'
  });

  // Save to localStorage
  useEffect(() => { saveToStorage('dash_officesData', officesData); }, [officesData]);
  useEffect(() => { saveToStorage('dash_events', events); }, [events]);
  useEffect(() => { saveToStorage('dash_users', users); }, [users]);
  useEffect(() => { saveToStorage('dash_activeMenu', activeMenu); }, [activeMenu]);

  const showToast = (message, type = 'info') => {
    if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
    setToast({ message, type, visible: true });
    toastTimerRef.current = setTimeout(() => {
      setToast(prev => ({ ...prev, visible: false }));
      toastTimerRef.current = null;
    }, 3200);
  };

  // Role helpers
  const isSuperAdmin = true;
  const isAdmin = true;
  const isUser = false;
  const canManageUsers = true;
  const canEditEvents = true;
  const canDeployEvents = true;

  const allProvinces = ['Ilocos Norte', 'Ilocos Sur', 'La Union', 'Pangasinan'];
  const activeEvent = events.find(e => e.deployment === 'Deployed');

  // Event functions
  const handleAddEvent = () => {
    if (!newEvent.name) { showToast('Event name is required.', 'warning'); return; }
    const newId = Math.max(...events.map(e => e.id), 0) + 1;
    const newStatus = newEvent.deployment === 'Deployed' ? 'active' : 'pending';
    setEvents([{ ...newEvent, id: newId, date: new Date().toLocaleDateString(), status: newStatus }, ...events]);
    setNewEvent({ id: null, name: '', alertLevel: '', category: '', deployment: 'Draft', provinces: [], status: 'pending' });
    setShowAddModal(false);
    showToast('Event created successfully.', 'success');
  };

  const handleDeleteEvent = (eventId) => {
    if (!window.confirm('Delete this event?')) return;
    setEvents(events.filter(e => e.id !== eventId));
    setShowDetailsModal(false);
    showToast('Event deleted.', 'error');
  };

  const handleEditEvent = (event) => {
    setNewEvent(event);
    setIsEditingEvent(true);
    setShowAddModal(true);
    setShowDetailsModal(false);
  };

  const handleDeployEvent = (eventId) => {
    setEvents(events.map(e => ({
      ...e,
      deployment: e.id === eventId ? 'Deployed' : (e.deployment === 'Deployed' ? 'Draft' : e.deployment)
    })));
    showToast('Event deployed.', 'success');
  };

  const filteredEvents = events.filter(event => {
    const term = searchTerm.toLowerCase();
    return event.name.toLowerCase().includes(term) || event.alertLevel?.toLowerCase().includes(term);
  });

  // User functions
  const handleSaveUser = () => {
    if (!userForm.name || !userForm.email || (!userForm.password && !isEditingUser)) {
      showToast('Name, email, and password are required.', 'warning');
      return;
    }
    if (isEditingUser) {
      setUsers(users.map(u => u.id === userForm.id ? { ...u, ...userForm, password: userForm.password || u.password } : u));
      showToast('User updated.', 'success');
    } else {
      const newId = Math.max(0, ...users.map(u => u.id)) + 1;
      setUsers([{ ...userForm, id: newId }, ...users]);
      showToast('User created.', 'success');
    }
    setShowUserModal(false);
    setUserForm({ id: null, name: '', email: '', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: '' });
  };

  const handleDeleteUser = (userId) => {
    if (!window.confirm('Delete this user?')) return;
    setUsers(users.filter(u => u.id !== userId));
    showToast('User deleted.', 'error');
  };

  // Report functions
  const handleGenerateReport = () => {
    showToast('Report generated!', 'success');
  };
  const handleDownloadDoc = () => {
    showToast('DOC downloaded!', 'success');
  };
  const handleExportExcel = () => {
    showToast('Excel exported!', 'success');
  };

  const getAlertColor = (level) => ({ RED: '#dc3545', BLUE: '#007bff' }[level] || '#28a745');
  const getStatusColor = (status) => ({ active: '#28a745', approved: '#0d6efd', pending: '#ffc107' }[status] || '#6c757d');
  const getEventStatusLabel = (event) => {
    if (event.deployment === 'Deployed') return 'Active';
    if (event.status === 'pending') return 'Pending';
    return event.deployment || 'Draft';
  };

  // Dashboard Content
  const DashboardContent = () => (
    <div>
      {toast.visible && (<div className={`toast-banner toast-${toast.type}`}><span>{toast.message}</span><button className="toast-close" onClick={() => setToast(prev => ({ ...prev, visible: false }))}>×</button></div>)}
      <div className="top-info-bar">
        <div className="top-info-item top-info-main"><span className="top-info-label">Current Event</span><span className="top-info-value">{activeEvent ? activeEvent.name : 'No Active Typhoon'}</span></div>
        <div className="top-info-item"><span className="top-info-label">Category</span><span className="top-info-value">{activeEvent?.category || '—'}</span></div>
        <div className="top-info-item"><span className="top-info-label">Alert Level</span><span className="top-info-value">{activeEvent?.alertLevel || '—'}</span></div>
        <div className="top-info-item"><span className="top-info-label">Status</span><span className="top-info-value">{activeEvent ? 'Active' : 'No Event'}</span></div>
      </div>
      <div className="info-bar">
        <div className="info-item"><span className="info-value">DOST Region 1</span></div>
        <div className="info-item"><span className="info-label">Disaster Management Dashboard</span></div>
      </div>
      <div className="notification-banner">
        <span className="notification-badge">SYSTEM READY</span>
        <span>Dashboard is fully operational. Use the menu to navigate.</span>
        <div style={{ display: 'flex', gap: '10px', marginLeft: '16px' }}>
          <button className="secondary-btn" onClick={handleGenerateReport}>📄 Generate Report</button>
          <button className="secondary-btn" onClick={handleDownloadDoc}>📥 Download DOC</button>
          <button className="secondary-btn" onClick={handleExportExcel}>📊 Export Excel</button>
        </div>
      </div>
      <div className="main-grid">
        <div className="card">
          <h3>Welcome to DOST Region 1 Disaster Management Dashboard</h3>
          <p>This dashboard helps monitor and manage disaster response across Region 1 (Ilocos Region).</p>
          <p>Use the sidebar to navigate between different sections.</p>
        </div>
      </div>
    </div>
  );

  // Typhoon Content
  const TyphoonContent = () => (
    <div className="events-management">
      <div className="events-header">
        <h1>Manage Events</h1>
        <div className="header-actions">
          <div className="search-box"><input type="text" placeholder="Search events..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></div>
          <button className="new-event-btn" onClick={() => setShowAddModal(true)}>+ New Event</button>
        </div>
      </div>
      <div className="filter-bar">
        <label>Status filter:</label>
        <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="all">All</option><option value="pending">Pending</option>
          <option value="approved">Approved</option><option value="active">Active</option>
        </select>
      </div>
      <div className="events-table-container">
        <table className="events-table">
          <thead><tr><th>EVENT NAME</th><th>DATE</th><th>ALERT LVL</th><th>STATUS</th><th>ACTIONS</th></tr></thead>
          <tbody>
            {filteredEvents.length > 0 ? filteredEvents.map(event => (
              <tr key={event.id}>
                <td className="event-name">{event.name}</td>
                <td>{event.date}</td>
                <td><span className="alert-badge" style={{ background: getAlertColor(event.alertLevel) }}>{event.alertLevel}</span></td>
                <td><span className="status-badge" style={{ background: getStatusColor(event.status) }}>{getEventStatusLabel(event)}</span></td>
                <td className="actions-cell">
                  <button className="action-btn view-btn" onClick={() => { setSelectedEvent(event); setShowDetailsModal(true); }}>View</button>
                  <button className="action-btn" onClick={() => handleEditEvent(event)}>Edit</button>
                  <button className="action-btn danger" onClick={() => handleDeleteEvent(event.id)}>Delete</button>
                  {event.status === 'approved' && <button className="action-btn deploy-btn" onClick={() => handleDeployEvent(event.id)}>Deploy</button>}
                </td>
              </tr>
            )) : <tr><td colSpan="5" style={{ textAlign: 'center', padding: '40px' }}>No events found. Click "+ New Event" to create one.</td></tr>}
          </tbody>
        </table>
      </div>

      {/* Add/Edit Modal */}
      {showAddModal && (
        <div className="modal-overlay" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><h3>{isEditingEvent ? 'Edit Event' : 'Add New Event'}</h3><button className="modal-close" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>×</button></div>
            <div className="form-group"><label>Event Name</label><input type="text" value={newEvent.name} onChange={(e) => setNewEvent({...newEvent, name: e.target.value})} placeholder="e.g., Typhoon Rolly" /></div>
            <div className="form-group"><label>Alert Level</label><select value={newEvent.alertLevel} onChange={(e) => setNewEvent({...newEvent, alertLevel: e.target.value})}><option value="">-- Select --</option><option>RED</option><option>BLUE</option><option>WHITE</option></select></div>
            <div className="form-group"><label>Category</label><select value={newEvent.category} onChange={(e) => setNewEvent({...newEvent, category: e.target.value})}><option value="">-- Select --</option><option>Super Typhoon</option><option>Typhoon</option><option>Tropical Storm</option></select></div>
            <div className="modal-buttons"><button className="success" onClick={handleAddEvent}>{isEditingEvent ? 'Save Changes' : 'Create Event'}</button><button onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>Cancel</button></div>
          </div>
        </div>
      )}

      {/* Details Modal */}
      {showDetailsModal && selectedEvent && (
        <div className="modal-overlay" onClick={() => setShowDetailsModal(false)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><h3>{selectedEvent.name}</h3><button className="modal-close" onClick={() => setShowDetailsModal(false)}>×</button></div>
            <div><strong>Date:</strong> {selectedEvent.date}</div>
            <div><strong>Alert Level:</strong> {selectedEvent.alertLevel}</div>
            <div><strong>Category:</strong> {selectedEvent.category}</div>
            <div><strong>Status:</strong> {selectedEvent.status}</div>
            <div><strong>Provinces:</strong> {selectedEvent.provinces?.join(', ')}</div>
            <div className="modal-buttons"><button onClick={() => setShowDetailsModal(false)}>Close</button></div>
          </div>
        </div>
      )}
    </div>
  );

  // Users Content
  const UsersContent = () => {
    const filteredUsers = users.filter(u => u.name.toLowerCase().includes(userSearchTerm.toLowerCase()) || u.email.toLowerCase().includes(userSearchTerm.toLowerCase()));
    return (
      <div className="events-management">
        <div className="events-header">
          <h1>User Management</h1>
          <div className="header-actions">
            <div className="search-box"><input type="text" placeholder="Search users..." value={userSearchTerm} onChange={(e) => setUserSearchTerm(e.target.value)} /></div>
            <button className="new-event-btn" onClick={() => { setUserForm({ id: null, name: '', email: '', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: '' }); setIsEditingUser(false); setShowUserModal(true); }}>+ New User</button>
          </div>
        </div>
        <div className="events-table-container">
          <table className="events-table">
            <thead><tr><th>Name</th><th>Email</th><th>Office</th><th>Role</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
              {filteredUsers.map(user => (
                <tr key={user.id}>
                  <td>{user.name}</td><td>{user.email}</td><td>{user.office}</td><td>{user.role}</td><td>{user.status}</td>
                  <td className="actions-cell">
                    <button className="view-btn" onClick={() => { setUserForm(user); setIsEditingUser(true); setShowUserModal(true); }}>Edit</button>
                    <button className="deploy-btn" onClick={() => handleDeleteUser(user.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {showUserModal && (
          <div className="modal-overlay" onClick={() => setShowUserModal(false)}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
              <div className="modal-header"><h3>{isEditingUser ? 'Edit User' : 'Create User'}</h3><button className="modal-close" onClick={() => setShowUserModal(false)}>×</button></div>
              <div className="form-group"><label>Name</label><input type="text" value={userForm.name} onChange={(e) => setUserForm({...userForm, name: e.target.value})} /></div>
              <div className="form-group"><label>Email</label><input type="email" value={userForm.email} onChange={(e) => setUserForm({...userForm, email: e.target.value})} /></div>
              <div className="form-group"><label>Office</label><select value={userForm.office} onChange={(e) => setUserForm({...userForm, office: e.target.value})}><option>PSTO-La Union</option><option>PSTO-Ilocos Norte</option><option>PSTO-Ilocos Sur</option><option>PSTO-Pangasinan</option></select></div>
              <div className="form-group"><label>Password</label><input type="password" value={userForm.password} onChange={(e) => setUserForm({...userForm, password: e.target.value})} /></div>
              <div className="form-group"><label>Role</label><select value={userForm.role} onChange={(e) => setUserForm({...userForm, role: e.target.value})}><option>SADMIN</option><option>ADMIN</option><option>USER</option></select></div>
              <div className="form-group"><label>Status</label><select value={userForm.status} onChange={(e) => setUserForm({...userForm, status: e.target.value})}><option>Active</option><option>Inactive</option></select></div>
              <div className="modal-buttons"><button className="success" onClick={handleSaveUser}>{isEditingUser ? 'Save' : 'Create'}</button><button onClick={() => setShowUserModal(false)}>Cancel</button></div>
            </div>
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="dashboard-container">
      <div className="sidebar-new">
        <div className="sidebar-logo"><h2>DOST Region 1</h2><p>Disaster Management</p></div>
        <nav className="sidebar-nav">
          <div className={`nav-item ${activeMenu === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveMenu('dashboard')}><span className="nav-icon">📊</span><span>Dashboard</span></div>
          <div className={`nav-item ${activeMenu === 'typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('typhoon')}><span className="nav-icon">🌊</span><span>Typhoon</span></div>
          {canManageUsers && <div className={`nav-item ${activeMenu === 'users' ? 'active' : ''}`} onClick={() => setActiveMenu('users')}><span className="nav-icon">👥</span><span>Users</span></div>}
        </nav>
        <div className="sidebar-footer">
          <div className="user-info"><div className="user-greeting">Hello, Admin</div><div className="user-role">SUPER ADMIN</div></div>
          <div className="user-actions"><div className="action-item logout" onClick={onLogout || (() => window.location.reload())}>🚪 Logout</div></div>
        </div>
      </div>
      <div className="main-content">
        {activeMenu === 'dashboard' && <DashboardContent />}
        {activeMenu === 'typhoon' && <TyphoonContent />}
        {activeMenu === 'users' && canManageUsers && <UsersContent />}
      </div>
    </div>
  );
};

export default Dashboard;
